/* Minimal Lottie loader fallback (small subset) - not full library.
   This lightweight shim only provides `loadAnimation` for our simple use-case.
   If you prefer the full library, replace this file with the official lottie.min.js.
*/
(function(global){
  function noop(){}
  function loadAnimation(opts){
    // very small SVG renderer fallback: if animationData has layers with shapes, render a static SVG placeholder
    var container = opts.container;
    container.innerHTML = '';
    var svg = document.createElementNS('http://www.w3.org/2000/svg','svg');
    svg.setAttribute('width', container.clientWidth || 200);
    svg.setAttribute('height', container.clientHeight || 200);
    svg.setAttribute('viewBox','0 0 400 400');
    var rect = document.createElementNS('http://www.w3.org/2000/svg','rect');
    rect.setAttribute('x','50'); rect.setAttribute('y','120'); rect.setAttribute('rx','12');
    rect.setAttribute('width','300'); rect.setAttribute('height','180'); rect.setAttribute('fill','#2563eb');
    svg.appendChild(rect);
    var roof = document.createElementNS('http://www.w3.org/2000/svg','polygon');
    roof.setAttribute('points','200,40 100,140 300,140'); roof.setAttribute('fill','#1e293b');
    svg.appendChild(roof);
    container.appendChild(svg);
    return { play: noop, stop: noop };
  }
  global.lottie = { loadAnimation: loadAnimation };
})(window);
